spec.expr:
clamp_min(
  (
    pve_cpu_usage_ratio{hostname="proxmox"}
    * on(id) group_left(name)
    pve_guest_info{hostname="proxmox", name=~"$hostname"}
  ) * 100,
  0
)

topk(
  20,
  (
    sum by (hostname, container_label_com_docker_compose_service) (
      rate(
        container_cpu_usage_seconds_total{
          job="cadvisor",
          hostname=~"$hostname",
          container_label_com_docker_compose_service!=""
        }[$__rate_interval]
      )
    ) * 100
  )
  /
  on (hostname) group_left()
  count by (hostname) (
    machine_cpu_cores{hostname=~"$hostname"}
  )
)

100 *
sum by (hostname, container_label_com_docker_compose_service) (
  container_memory_working_set_bytes{
    job="cadvisor",
    hostname=~"$hostname",
    container_label_com_docker_compose_service!=""
  }
)
/
on (hostname) group_left()
max by (hostname) (
  machine_memory_bytes{job="cadvisor", hostname=~"$hostname"}
)

label_replace(( ups_days_since_last_ob_lower_bound
    and on(instance) (ups_ob_seen_window_60d == bool 0)
  ), "prefix", "≥ ", "__name__", ".*" )
or label_replace(( ups_days_since_last_ob_lower_bound
    and on(instance) (ups_ob_seen_window_60d == bool 1)
  ), "prefix", "", "__name__", ".*" )

(
  sum by (disk) (
    label_join(sum_over_time(disk:spindown_event:1[1d]), "disk", " - ", "hostname", "shortdev")
  )
)
or on (disk)
max by (disk) (
  label_join(
    label_replace(disk_power_state_value{type="hdd"}, "shortdev", "$1", "device", "/dev/(.+)"),
    "disk", " - ", "hostname", "shortdev"
  ) * 0
)

